// ดึง Weather จาก node ต้นทาง, AQI จาก Merge output (index 0 = merged item)
const weatherRaw = $('Get Weather').first().json;

// WAQI response อยู่ใน $('Get AQI / PM2.5')
const aqiRaw = $('Get AQI / PM2.5').first().json;

// Weather fields
const temp        = weatherRaw?.main?.temp                 ?? null;
const humidity    = weatherRaw?.main?.humidity             ?? null;
const windSpeed   = weatherRaw?.wind?.speed                ?? null;
const windDeg     = weatherRaw?.wind?.deg                  ?? null;
const weatherDesc = weatherRaw?.weather?.[0]?.description  ?? '';

// AQI fields — WAQI returns { status:"ok", data:{ aqi, iaqi:{...}, city:{name} } }
const aqiData     = aqiRaw?.data    ?? {};
const iaqi        = aqiData?.iaqi   ?? {};
const aqiValue    = aqiData?.aqi    ?? null;
const pm25        = iaqi?.pm25?.v   ?? null;
const pm10        = iaqi?.pm10?.v   ?? null;
const o3          = iaqi?.o3?.v     ?? null;
const no2         = iaqi?.no2?.v    ?? null;
const so2         = iaqi?.so2?.v    ?? null;
const stationName = aqiData?.city?.name ?? 'Bangkok';

// AQI Level classification
function classifyAQI(v) {
  if (v === null) return { level: 'ไม่มีข้อมูล',         color: 0x95a5a6, emoji: '❓', risk: 'ไม่ทราบ',            advice: 'ไม่มีข้อมูล' };
  if (v <= 50)   return { level: 'ดีมาก',                color: 0x2ecc71, emoji: '🟢', risk: 'ต่ำ',                advice: 'คุณภาพอากาศดีเยี่ยม สามารถทำกิจกรรมกลางแจ้งได้ตามปกติ' };
  if (v <= 100)  return { level: 'ปานกลาง',              color: 0xf1c40f, emoji: '🟡', risk: 'ปานกลาง',            advice: 'กลุ่มเสี่ยง (ผู้ป่วยหอบหืด ผู้สูงอายุ เด็กเล็ก) ควรระวัง' };
  if (v <= 150)  return { level: 'ไม่ดีต่อกลุ่มเสี่ยง', color: 0xe67e22, emoji: '🟠', risk: 'สูงต่อกลุ่มเสี่ยง', advice: 'กลุ่มเสี่ยงควรลดกิจกรรมกลางแจ้ง ควรสวมหน้ากาก N95' };
  if (v <= 200)  return { level: 'ไม่ดี',                color: 0xe74c3c, emoji: '🔴', risk: 'สูง',                advice: 'ทุกคนควรลดกิจกรรมกลางแจ้ง สวมหน้ากาก N95 หลีกเลี่ยงการออกกำลังกาย' };
  if (v <= 300)  return { level: 'แย่มาก',               color: 0x9b59b6, emoji: '🟣', risk: 'สูงมาก',            advice: 'หลีกเลี่ยงกิจกรรมกลางแจ้งทั้งหมด ปิดหน้าต่างบ้าน เปิดเครื่องฟอกอากาศ' };
  return           { level: 'อันตราย',                   color: 0x7f0000, emoji: '⛔', risk: 'อันตราย',           advice: 'อยู่ในอาคารและปิดหน้าต่างประตูทั้งหมด เด็กและผู้สูงอายุห้ามออกนอกบ้านเด็ดขาด' };
}

function classifyPM25(v) {
  if (v === null) return { level: 'ไม่มีข้อมูล' };
  if (v <= 25)   return { level: 'ดี (≤25)' };
  if (v <= 37)   return { level: 'ปานกลาง (≤37)' };
  if (v <= 50)   return { level: 'เริ่มมีผล (≤50)' };
  if (v <= 90)   return { level: 'มีผลต่อสุขภาพ (≤90)' };
  return           { level: 'อันตราย (>90)' };
}

function windDirection(deg) {
  if (deg === null) return '-';
  const dirs = ['N','NE','E','SE','S','SW','W','NW'];
  return dirs[Math.round(deg / 45) % 8];
}

const aqiMeta  = classifyAQI(aqiValue);
const pm25Meta = classifyPM25(pm25);

// Trend
const staticData = $getWorkflowStaticData('global');
const prevPm25 = staticData.prevPm25 ? parseFloat(staticData.prevPm25) : null;
let trend = 'stable', trendEmoji = '➡️';
if (prevPm25 !== null && pm25 !== null) {
  if (pm25 - prevPm25 >  5) { trend = 'rising';  trendEmoji = '📈'; }
  if (prevPm25 - pm25 >  5) { trend = 'falling'; trendEmoji = '📉'; }
}
staticData.prevPm25 = String(pm25 ?? 0);

// Alert conditions
const alertPM25   = pm25     !== null && pm25     > 50;
const alertAQI    = aqiValue !== null && aqiValue > 100;
const alertTemp   = temp     !== null && temp     > 35;
const alertO3     = o3       !== null && o3       > 100;
const shouldAlert = alertPM25 || alertAQI || alertTemp || alertO3;

const reasons = [];
if (alertPM25) reasons.push(`PM2.5 = **${pm25}** µg/m³ (เกินมาตรฐาน 50)`);
if (alertAQI)  reasons.push(`AQI = **${aqiValue}** (เกินระดับปลอดภัย 100)`);
if (alertTemp) reasons.push(`อุณหภูมิ = **${temp}°C** (ร้อนจัด)`);
if (alertO3)   reasons.push(`Ozone = **${o3}** µg/m³ (เกินมาตรฐาน 100)`);

return [{
  json: {
    temp, humidity, windSpeed, windDeg, weatherDesc,
    aqiValue, pm25, pm10, o3, no2, so2, stationName,
    aqiMeta, pm25Meta, trend, trendEmoji,
    shouldAlert, reasons,
    windDirText: windDirection(windDeg),
    timestamp:   new Date().toISOString(),
    timestampTH: new Date().toLocaleString('th-TH', { timeZone: 'Asia/Bangkok' }),
  }
}];

const COOLDOWN_MINUTES = 60;
const staticData    = $getWorkflowStaticData('global');
const lastSent      = staticData.lastAlertSent ? parseInt(staticData.lastAlertSent, 10) : 0;
const minutesPassed = (Date.now() - lastSent) / 60000;

if (minutesPassed < COOLDOWN_MINUTES) {
  return []; // หยุด — cooldown ยังไม่หมด
}

return $input.all();

const d = $json;

function buildBar(value, max, segments = 10) {
  if (value === null || value === undefined) return '░'.repeat(segments);
  const filled = Math.min(Math.round((value / max) * segments), segments);
  return '█'.repeat(filled) + '░'.repeat(segments - filled);
}

function windText(speed, dir) {
  if (speed === null || speed === undefined) return 'ไม่มีข้อมูล';
  return `${speed} m/s ${dir}`;
}

function fieldVal(v, unit = 'µg/m³') {
  if (v === null || v === undefined) return 'ไม่มีข้อมูล';
  return `${v} ${unit}`;
}

// Description lines — only include forecast if value exists
const descLines = [
  `**${d.aqiMeta.level}** | ความเสี่ยง: ${d.aqiMeta.risk}`,
  '',
];

if (d.reasons && d.reasons.length > 0) {
  descLines.push(...d.reasons);
} else {
  descLines.push('ตรวจพบค่าเกินมาตรฐาน');
}

// Only add forecast line if value is a real number
if (d.forecastPm25 !== null && d.forecastPm25 !== undefined && !isNaN(Number(d.forecastPm25))) {
  descLines.push(`\n> 🔭 **พยากรณ์ PM2.5 พรุ่งนี้:** ${d.forecastPm25} µg/m³`);
}

const pm25Bar = buildBar(d.pm25, 150);
const aqiBar  = buildBar(d.aqiValue, 300);

const body = {
  embeds: [{
    title: `${d.aqiMeta.emoji} Air Quality Alert — กรุงเทพมหานคร`,
    description: descLines.join('\n'),
    color: d.aqiMeta.color,
    fields: [
      {
        name: '🌫 PM2.5 (µg/m³)',
        value: `**${d.pm25 ?? '-'}** µg/m³\n\`${pm25Bar}\` ${d.pm25Meta?.level ?? ''}`,
        inline: false
      },
      {
        name: '📊 AQI',
        value: `**${d.aqiValue ?? '-'}**\n\`${aqiBar}\``,
        inline: true
      },
      {
        name: '🌡 อุณหภูมิ',
        value: `**${d.temp ?? '-'}°C** 💧${d.humidity ?? '-'}%`,
        inline: true
      },
      {
        name: '💨 ลม',
        value: windText(d.windSpeed, d.windDirText),
        inline: true
      },
      {
        name: '🏭 PM10',
        value: fieldVal(d.pm10),
        inline: true
      },
      {
        name: '☁️ Ozone (O₃)',
        value: fieldVal(d.o3),
        inline: true
      },
      {
        name: '🔬 NO₂',
        value: fieldVal(d.no2),
        inline: true
      },
      {
        name: '📈 แนวโน้ม PM2.5',
        value: `${d.trendEmoji} ${d.trend === 'rising' ? 'กำลังเพิ่มขึ้น' : d.trend === 'falling' ? 'กำลังลดลง' : 'ทรงตัว'}`,
        inline: true
      },
      {
        name: '💡 คำแนะนำ',
        value: d.aqiMeta?.advice ?? '-',
        inline: false
      }
    ],
    footer: {
      text: `📍 สถานี: ${d.stationName} | อัปเดต: ${d.timestampTH}`
    },
    timestamp: d.timestamp
  }]
};

return [{ json: { body } }];
